1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const basePremiumForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
18	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const BLOCK_SIZE = 3;
22	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
25	
26	const componentGroupPremium = (type: string, count: number): number =>
27	  count === BLOCK_SIZE ? BLOCK_OF_THREE_BASE_PREMIUM : count * basePremiumForType(type);
28	
29	const groupByType = (items: Item[]): Map<string, number> => {
30	  const counts = new Map<string, number>();
31	  for (const item of items) {
32	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
33	  }
34	  return counts;
35	};
36	
37	const sum = (values: number[]): number => values.reduce((total, value) => total + value, 0);
38	
39	const policyBasePremium = (items: Item[]): number => {
40	  const mainItems = items.filter((item) => !isComponent(item));
41	  const componentItems = items.filter(isComponent);
42	  const componentCounts = groupByType(componentItems);
43	
44	  const mainTotal = sum(mainItems.map(itemBasePremium));
45	  const componentTotal = sum(
46	    [...componentCounts].map(([type, count]) => componentGroupPremium(type, count)),
47	  );
48	
49	  return mainTotal + componentTotal;
50	};
51	
52	const CURSE_SURCHARGE_RATE = 0.5;
53	
54	const itemSurcharges = (item: Item): number => {
55	  let surcharge = 0;
56	  if (item.cursed) surcharge += itemBasePremium(item) * CURSE_SURCHARGE_RATE;
57	  return surcharge;
58	};
59	
60	const quotePremium = (items: Item[]): number => {
61	  const basePremium = policyBasePremium(items);
62	  const surcharges = sum(items.map(itemSurcharges));
63	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
64	  const premiumBeforeFee = Math.ceil(basePremium + surcharges + firstInsurance);
65	  return premiumBeforeFee + PROCESSING_FEE;
66	};
67	
68	export const runScenario = (scenario: Scenario): unknown => {
69	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
70	  return { results };
71	};
